import React, { useState } from "react";
import { register } from "../services/authService";
import "./AuthPage.css";

/**
 * RegisterPage
 * ────────────
 * Sign-up form with full validation.
 * Fields: Full Name, Username, Email, Password, Confirm Password.
 *
 * Props:
 *   onLogin   {Function}  – called with the user object after successful registration
 *   onGoLogin {Function}  – switches the view back to the Login page
 */
function RegisterPage({ onLogin, onGoLogin }) {
  const [form, setForm] = useState({
    full_name:        "",
    username:         "",
    email:            "",
    password:         "",
    confirm_password: "",
  });
  const [errors, setErrors]     = useState({});
  const [apiError, setApiError] = useState("");
  const [loading, setLoading]   = useState(false);
  const [showPwd, setShowPwd]   = useState(false);
  const [showCPwd, setShowCPwd] = useState(false);

  const set = (field) => (e) => {
    setForm((prev) => ({ ...prev, [field]: e.target.value }));
    setErrors((prev) => ({ ...prev, [field]: "" }));
    setApiError("");
  };

  const validate = () => {
    const errs = {};
    if (!form.full_name.trim())
      errs.full_name = "Full name is required.";

    if (!form.username.trim())
      errs.username = "Username is required.";
    else if (!/^[a-zA-Z0-9_]{3,30}$/.test(form.username.trim()))
      errs.username = "3-30 chars: letters, numbers, underscores only.";

    if (!form.email.trim())
      errs.email = "Email is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email.trim()))
      errs.email = "Enter a valid email address.";

    if (!form.password)
      errs.password = "Password is required.";
    else if (form.password.length < 8)
      errs.password = "Password must be at least 8 characters.";

    if (!form.confirm_password)
      errs.confirm_password = "Please confirm your password.";
    else if (form.password !== form.confirm_password)
      errs.confirm_password = "Passwords do not match.";

    return errs;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }

    setLoading(true);
    try {
      const user = await register({
        full_name:        form.full_name.trim(),
        username:         form.username.trim(),
        email:            form.email.trim().toLowerCase(),
        password:         form.password,
        confirm_password: form.confirm_password,
      });
      onLogin(user);
    } catch (err) {
      // Backend may return field-level errors
      if (err.message) setApiError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card auth-card--wide">
        {/* Header */}
        <div className="auth-card__header">
          <span className="auth-card__icon">☑</span>
          <h1 className="auth-card__title">Create Account</h1>
          <p className="auth-card__subtitle">Sign up to start managing your tasks.</p>
        </div>

        {apiError && <div className="auth-alert auth-alert--error">{apiError}</div>}

        <form onSubmit={handleSubmit} noValidate className="auth-form">
          {/* Full Name */}
          <div className={`auth-field ${errors.full_name ? "auth-field--error" : ""}`}>
            <label htmlFor="reg-fullname">Full Name</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">🪪</span>
              <input
                id="reg-fullname"
                type="text"
                placeholder="Your full name"
                value={form.full_name}
                onChange={set("full_name")}
                autoFocus
              />
            </div>
            {errors.full_name && <p className="auth-field__error">{errors.full_name}</p>}
          </div>

          {/* Username */}
          <div className={`auth-field ${errors.username ? "auth-field--error" : ""}`}>
            <label htmlFor="reg-username">Username</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">👤</span>
              <input
                id="reg-username"
                type="text"
                placeholder="Choose a username (e.g. john_doe)"
                value={form.username}
                onChange={set("username")}
                autoComplete="username"
              />
            </div>
            {errors.username && <p className="auth-field__error">{errors.username}</p>}
          </div>

          {/* Email */}
          <div className={`auth-field ${errors.email ? "auth-field--error" : ""}`}>
            <label htmlFor="reg-email">Email Address</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">✉️</span>
              <input
                id="reg-email"
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={set("email")}
                autoComplete="email"
              />
            </div>
            {errors.email && <p className="auth-field__error">{errors.email}</p>}
          </div>

          {/* Password */}
          <div className={`auth-field ${errors.password ? "auth-field--error" : ""}`}>
            <label htmlFor="reg-password">Password</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">🔒</span>
              <input
                id="reg-password"
                type={showPwd ? "text" : "password"}
                placeholder="Min. 8 characters"
                value={form.password}
                onChange={set("password")}
                autoComplete="new-password"
              />
              <button
                type="button"
                className="auth-input-toggle"
                onClick={() => setShowPwd((v) => !v)}
                tabIndex={-1}
              >
                {showPwd ? "🙈" : "👁️"}
              </button>
            </div>
            {errors.password && <p className="auth-field__error">{errors.password}</p>}
            {/* Strength hint */}
            {form.password && (
              <div className="auth-strength">
                <div
                  className={`auth-strength__bar auth-strength__bar--${
                    form.password.length >= 12 ? "strong" :
                    form.password.length >= 8  ? "medium" : "weak"
                  }`}
                />
                <span className="auth-strength__label">
                  {form.password.length >= 12 ? "Strong" :
                   form.password.length >= 8  ? "Medium" : "Weak"}
                </span>
              </div>
            )}
          </div>

          {/* Confirm Password */}
          <div className={`auth-field ${errors.confirm_password ? "auth-field--error" : ""}`}>
            <label htmlFor="reg-confirm">Confirm Password</label>
            <div className="auth-input-wrap">
              <span className="auth-input-icon">🔐</span>
              <input
                id="reg-confirm"
                type={showCPwd ? "text" : "password"}
                placeholder="Re-enter your password"
                value={form.confirm_password}
                onChange={set("confirm_password")}
                autoComplete="new-password"
              />
              <button
                type="button"
                className="auth-input-toggle"
                onClick={() => setShowCPwd((v) => !v)}
                tabIndex={-1}
              >
                {showCPwd ? "🙈" : "👁️"}
              </button>
            </div>
            {errors.confirm_password && (
              <p className="auth-field__error">{errors.confirm_password}</p>
            )}
          </div>

          <button type="submit" className="auth-btn" disabled={loading}>
            {loading ? <span className="auth-btn__spinner" /> : null}
            {loading ? "Creating account…" : "Create Account"}
          </button>
        </form>

        <div className="auth-card__footer">
          <p>
            Already have an account?{" "}
            <button className="auth-link" onClick={onGoLogin}>
              Sign in here
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}

export default RegisterPage;
